#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>

pthread_key_t key;

void destructor(void *val) {
    printf("Destructor: freeing %d\n", *(int *)val);
    free(val);
}

void *worker(void *arg) {
    int id = *(int *)arg;
    int *val = malloc(sizeof(int));
    *val = id * 100;
    pthread_setspecific(key, val);
    int *got = (int *)pthread_getspecific(key);
    printf("Thread %d: TLS value = %d\n", id, *got);
    return NULL;
}

int main(void) {
    pthread_key_create(&key, destructor);
    pthread_t t[3];
    int ids[3] = {1, 2, 3};
    for (int i = 0; i < 3; i++) {
        pthread_create(&t[i], NULL, worker, &ids[i]);
        pthread_join(t[i], NULL);
    }
    pthread_key_delete(key);
    return 0;
}

